import{c as t,a0 as s,U as i,j as n,g as o,n as r,o as d,m as c}from"./chunks/framework.Dvkoa_vi.js";const f=JSON.parse('{"title":"Parte Vue 3 con TypeScript — Sesiones 9 a 13","description":"Fundamentos de Vue 3 con TypeScript para el curso de normalización (sesiones 9 a 13 del temario global).","frontmatter":{"title":"Parte Vue 3 con TypeScript — Sesiones 9 a 13","description":"Fundamentos de Vue 3 con TypeScript para el curso de normalización (sesiones 9 a 13 del temario global).","outline":"deep"},"headers":[],"relativePath":"03-vue/index.md","filePath":"03-vue/index.md"}'),l={name:"03-vue/index.md"};function p(u,e,m,v,h,y){const a=s("CopyOrDownloadAsMarkdownButtons");return i(),n("div",null,[e[0]||(e[0]=o("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/03-vue.md for this page in Markdown format",-1)),e[1]||(e[1]=o("h1",{id:"parte-vue-3-con-typescript",tabindex:"-1"},[r("Parte Vue 3 con TypeScript "),o("a",{class:"header-anchor",href:"#parte-vue-3-con-typescript","aria-label":"Permalink to “Parte Vue 3 con TypeScript”"},"​")],-1)),d(a),e[2]||(e[2]=c('<p>Esta sección cubre las <strong>sesiones 9 a 13</strong> del curso, dedicadas a Vue 3 con TypeScript. Continúa tras la <a href="./../02-dotnet/">Parte .NET</a> y precede a la <a href="./../04-integracion/">Integración full-stack</a>.</p><h2 id="objetivos-del-modulo" tabindex="-1">Objetivos del módulo <a class="header-anchor" href="#objetivos-del-modulo" aria-label="Permalink to “Objetivos del módulo”">​</a></h2><div class="info custom-block"><p class="custom-block-title">CONTEXTO</p><p>Al finalizar este bloque, el alumno será capaz de:</p><ul><li>Crear componentes Vue 3 con TypeScript y Composition API.</li><li>Trabajar con reactividad, directivas y eventos.</li><li>Comunicar componentes mediante Props, Emits y <code>defineModel</code>.</li><li>Aplicar propiedades computadas y watchers.</li><li>Estructurar aplicaciones con la arquitectura Vista → Composable → Servicio.</li><li>Utilizar componentes internos de la UA (<code>@vueua/components</code>).</li></ul></div><h2 id="sesiones-de-este-bloque" tabindex="-1">Sesiones de este bloque <a class="header-anchor" href="#sesiones-de-este-bloque" aria-label="Permalink to “Sesiones de este bloque”">​</a></h2><table tabindex="0"><thead><tr><th>Sesión</th><th>Título</th><th>Duración</th></tr></thead><tbody><tr><td><a href="./sesiones/sesion-09-vue-typescript-fundamentos/">Sesión 9: Vue 3, TypeScript y primer componente</a></td><td>Estructura <code>.vue</code>, TypeScript básico, reactividad e interpolación</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-10-directivas-eventos/">Sesión 10: Directivas, eventos y datos</a></td><td>Interfaces, directivas, <code>v-model</code>, eventos y métodos de arrays</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-11-componentes-estado/">Sesión 11: Componentes y comunicación</a></td><td><code>computed</code>, Props, Emits, <code>defineModel</code>, watchers, lifecycle, slots</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-12-arquitectura-apis/">Sesión 12: Arquitectura de componentes y servicios</a></td><td>Composables vs Servicios, Vista → Composable → Servicio, depuración</td><td>1 h 30 min</td></tr><tr><td><a href="./sesiones/sesion-13-componentes-ua/">Sesión 13: Otros componentes internos</a></td><td><code>@vueua/components</code> — modales, toasts, BotonLoading, Teleport</td><td>1 h 30 min</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CONTINUACIÓN EN INTEGRACIÓN</p><p>Los temas de llamadas a la API (<code>useAxios</code>), validación de formularios (<code>useGestionFormularios</code>) y estado global (Pinia) se cubren en las sesiones de <strong>Integración full-stack</strong> (14-17) y <strong>Sesiones avanzadas</strong> (18-25), donde se ven de extremo a extremo con .NET y Oracle.</p></div><h2 id="requisitos-previos" tabindex="-1">Requisitos previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to “Requisitos previos”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><ul><li>Visual Studio Code con la extensión <strong>Vue - Official</strong>.</li><li>Node.js 18+ y <strong>pnpm 10.22.0</strong> (recomendado vía Corepack).</li><li>Proyecto creado desde la <strong>plantilla UA</strong> (<code>PlantillaMVCCore</code>).</li><li>Conocimientos básicos de HTML y CSS.</li></ul></div><h2 id="material-de-apoyo" tabindex="-1">Material de apoyo <a class="header-anchor" href="#material-de-apoyo" aria-label="Permalink to “Material de apoyo”">​</a></h2><ul><li><a href="./test/">Tests y evaluación</a> — Banco de preguntas, autoevaluación y práctica IA-fix por sesión.</li></ul>',10))])}const S=t(l,[["render",p]]);export{f as __pageData,S as default};
